glsl.vertex:
varying vec2 vUv;
void main(){
 vUv=uv;
 gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0);
}

glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float uTime;
float hash(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453123);}
float noise(vec2 p){vec2 i=floor(p);vec2 f=fract(p);vec2 u=f*f*(3.0-2.0*f);return mix(mix(hash(i),hash(i+vec2(1.0,0.0)),u.x),mix(hash(i+vec2(0.0,1.0)),hash(i+vec2(1.0,1.0)),u.x),u.y);}
void main(){
 vec2 p=vUv;
 float n=noise(p*10.0)+0.5*noise(p*23.0+3.1)+0.25*noise(p*47.0);
 float cloud=smoothstep(0.18,1.25,n);
 vec3 ochre=vec3(0.73,0.50,0.25);
 vec3 pale=vec3(0.86,0.68,0.42);
 vec3 green=vec3(0.42,0.57,0.43);
 float diagonal=abs((p.y-0.55)+(p.x-0.5)*0.28);
 vec3 col=mix(ochre,pale,cloud*0.55);
 col=mix(col,green,0.07*smoothstep(0.55,0.0,diagonal));
 float paper=hash(floor(p*vec2(420.0,260.0)))*0.055;
 float edge=1.0-0.10*smoothstep(0.44,0.76,length(p-0.5));
 gl_FragColor=vec4((col+paper)*edge,1.0);
}
